import acm.program.*;
import acm.graphics.*;
import java.awt.*;
import java.awt.event.*;

public class MiniBreakout extends GraphicsProgram {
    private static final int WIDTH = 400, HEIGHT = 600;
    private static final int PADDLE_W = 60, PADDLE_H = 10;
    private static final int DIAM = 12;
    private static final double FPS = 60.0;

    private GRect paddle;
    private GOval ball;
    private double dx = 3.0, dy = 3.5;

    public void run() {
        setSize(WIDTH, HEIGHT);
        setupPaddle();
        setupBall();
        addMouseListeners();
        while (true) {
            ball.move(dx, dy);
            // Wall bounces
            if (ball.getX() <= 0 || ball.getX() + DIAM >= getWidth()) dx = -dx;
            if (ball.getY() <= 0) dy = -dy;
            if (ball.getY() + DIAM >= getHeight()) {
                // reset ball
                ball.setLocation(getWidth() / 2.0 - DIAM / 2.0, getHeight() / 2.0 - DIAM / 2.0);
                dx = 3.0; dy = 3.5;
            }
            // Collision sampling
            GObject hit = checkBallCollision();
            if (hit == paddle) {
                dy = -Math.abs(dy);
                // Optional: tweak dx based on where the ball hits the paddle
            }
            pause(1000.0 / FPS);
        }
    }

    private void setupPaddle() {
        paddle = new GRect(PADDLE_W, PADDLE_H);
        paddle.setFilled(true); paddle.setFillColor(Color.BLACK);
        add(paddle, getWidth() / 2.0 - PADDLE_W / 2.0, getHeight() - 40);
    }

    private void setupBall() {
        ball = new GOval(DIAM, DIAM);
        ball.setFilled(true); ball.setFillColor(Color.RED);
        add(ball, getWidth() / 2.0 - DIAM / 2.0, getHeight() / 2.0 - DIAM / 2.0);
    }

    private GObject checkBallCollision() {
        double x = ball.getX();
        double y = ball.getY();
        GObject obj;
        // bottom-center
        obj = getElementAt(x + DIAM / 2.0, y + DIAM + 1);
        if (obj != null) return obj;
        // left side
        obj = getElementAt(x - 1, y + DIAM / 2.0);
        if (obj != null) { dx = Math.abs(dx); return obj; }
        // right side
        obj = getElementAt(x + DIAM + 1, y + DIAM / 2.0);
        if (obj != null) { dx = -Math.abs(dx); return obj; }
        return null;
    }

    public void mouseMoved(MouseEvent e) {
        double newX = e.getX() - PADDLE_W / 2.0;
        newX = Math.max(0, Math.min(newX, getWidth() - PADDLE_W));
        paddle.setLocation(newX, paddle.getY());
    }
}

