public class TimerBounce extends GraphicsProgram {
    private GRect box;
    private JButton startBtn, stopBtn;
    private Timer timer;
    private double vx = 3, vy = 2;

    public void init() {
        box = new GRect(20, 20, 40, 40);
        box.setFilled(true);
        add(box);
        startBtn = new JButton("Start");
        stopBtn = new JButton("Stop");
        add(startBtn, SOUTH);
        add(stopBtn, SOUTH);
        addActionListeners();
        timer = new Timer(20, this);
    }

    public void actionPerformed(ActionEvent e) {
        Object src = e.getSource();
        if (src == startBtn) {
            timer.start();
        } else if (src == stopBtn) {
            timer.stop();
        } else if (src == timer) {
            step();
        }
    }

    private void step() {
        box.move(vx, vy);
        if (box.getX() < 0 || box.getX() + box.getWidth() > getWidth()) {
            vx = -vx;
        }
        if (box.getY() < 0 || box.getY() + box.getHeight() > getHeight()) {
            vy = -vy;
        }
    }
}

class Counter { int n; Counter(int n){ this.n = n; } }

static void bump(Counter c) { c.n = 5; }
static void rebind(Counter c) { c = new Counter(100); }

public static void main(String[] args) {
  Counter c = new Counter(0);
  bump(c); // mutates heap object
  System.out.println(c.n); // 5
  rebind(c); // reassigns local copy of reference only
  System.out.println(c.n); // still 5
}

