        String[] fields = line.split("\t", -1);
        if (fields.length > columnIndex && !fields[columnIndex].isEmpty()) {
          sum += Double.parseDouble(fields[columnIndex]);
        }
      }
    }
    System.out.println("Sum: " + sum);
  }
}

