import java.util.*;

public class InvertMapDemo {
  public static <K,V> Map<V, Set<K>> invert(Map<K,V> original) {
    Map<V, Set<K>> inverse = new HashMap<>();
    for (Map.Entry<K,V> e : original.entrySet()) {
      V v = e.getValue();
      K k = e.getKey();
      inverse.computeIfAbsent(v, key -> new HashSet<>()).add(k);
    }
    return inverse;
  }

  public static void main(String[] args) {
    Map<String,String> advisor = new HashMap<>();
    advisor.put("Alice", "ProfX");
    advisor.put("Bob", "ProfY");
    advisor.put("Cara", "ProfX");
    System.out.println(invert(advisor));
  }
}

